# This list is too large. Let me batch insert it
ALL_ITEMS = BALI + SUNDA + PADANG + JAWA + NUSA

def main():
    conn = sqlite3.connect(DB_PATH)
    cur = conn.cursor()
    
    # Get existing names
    cur.execute("SELECT name_id FROM food_item")
    existing = {r[0] for r in cur.fetchall()}
    print(f"Existing items: {len(existing)}")
    
    inserted = 0
    skipped = 0
    for item in ALL_ITEMS:
        if item[0] in existing:
            skipped += 1
            continue
        
        cur.execute("""
            INSERT INTO food_item
                (name_id, name_en, category, prep_type, calories, protein_g, carbs_g, fat_g, fiber_g,
                 price_pasar_min, price_pasar_max, tags_json, cuisine_tags_json, active,
                 verification_status, source_url)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 1, 'auto_verified', 'seed_v3')
        """, (
            item[0], None, item[1], "buy_ready",
            item[2], item[3], item[4], item[5], item[6],
            item[7], item[8],
            json.dumps(item[9]), json.dumps(item[10]),
        ))
        inserted += 1
    
    conn.commit()
    
    cur.execute("SELECT COUNT(*) FROM food_item")
    total = cur.fetchone()[0]
    cur.execute("SELECT COUNT(*) FROM food_item WHERE cuisine_tags_json LIKE '%bali%'")
    bali = cur.fetchone()[0]
    conn.close()
    
    print(f"Inserted: {inserted}")
    print(f"Skipped: {skipped}")
    print(f"Total: {total}")
    print(f"Bali cuisine: {bali}")

if __name__ == "__main__":
    main()